const item = items[0];
return [{
  json: {
    title: item.json.title,
    content: item.json.content
  }
}];

let keywords = $json.query
  .toLowerCase()
  .replace(/[^\w\s]/g, "")
  .split(/\s+/)
  .filter(w => !["hvad","er","og","i","på","til","for","med","about","tell","me"].includes(w));

if (keywords.length === 0) keywords = [$json.query.toLowerCase()];

return [{ json: { query: $json.query, keywords } }];

if (items.length === 0) {
  return [{
    json: {
      fallback: true,
      context: [],
      message: "No retrieval matches"
    }
  }];
}

return items;

const weightVector = 0.7;
const weightGraph = 0.3;

const map = {};

for (const item of items) {

  const title = item.json.title;

  if (!map[title]) {
    map[title] = {
      title,
      vectorScore: 0,
      graphScore: 0
    };
  }

  if (item.json.source === "vector") {
    map[title].vectorScore = item.json.score || 1;
  }

  if (item.json.source === "graph") {
    map[title].graphScore = 1;
  }
}

const result = Object.values(map).map(d => {
  d.finalScore =
    d.vectorScore * weightVector +
    d.graphScore * weightGraph;
  return { json: d };
});

result.sort((a,b)=> b.json.finalScore - a.json.finalScore);

return result.slice(0,5);

const query = items[0].json.query.toLowerCase();
const keywords = query.replace(/[^\w\s]/g, '').split(/\s+/);
 const mainKeyword = keywords.filter(w => 
  !['hvad', 'er', 'og', 'i', 'på', 'til', 'for', 'med', 'om', 'en', 'et'].includes(w)
)[0] || keywords[0];
return [{ json: { query: mainKeyword } }];

